# fmt: off
TRANSLATIONS: dict[int, dict] = {
351: {"nativeDefinition": "If you try hard enough, you can achieve your goal.", "japaneseMeaning": "意志あれば道は開ける", "etymology": "where there's a will there's a way（意志があるところに道がある）のことわざ。", "examples": {"B": "彼は試験に合格できると強く信じている。全力を尽くしているから。", "C": "次のフライトに間に合わないと思う？意志あれば道は開けるよ。", "D": "十分な努力があれば目標は達成される"}},
352: {"nativeDefinition": "To sound extremely unpleasant to someone.", "japaneseMeaning": "（人の）耳に痛い、聞くに耐えない", "etymology": "make ears bleed（耳を出血させる）が比喩的に聞くに耐えないことを表す。", "examples": {"B": "コーヒーを飲むときにズルズル音を立てないで。耳に痛い。", "C": "最近の子どもたちが聞く音楽は本当に耳に痛い。", "D": "誰かにとって不快な音"}},
353: {"nativeDefinition": "To deceive someone.", "japaneseMeaning": "（人を）欺く、目くらましをする", "etymology": "pull the wool over one's eyes（目に毛糸を被せる）が比喩的に欺くことを表す。", "examples": {"B": "政府がまだ国民を欺こうとしているなんて信じられない。", "C": "ジョージは僕を欺こうとしたけど、何が起きているかはもうわかっていた。", "D": "誰かを欺く"}},
354: {"nativeDefinition": "To organize one's affairs properly.", "japaneseMeaning": "身の回りを整える、家の中を片付ける", "etymology": "put one's house in order（家を整える）が比喩的に身の回りを整えることを表す。", "examples": {"B": "ベネズエラは他国を攻撃する前に、まず国内の問題を片付けるべきだ。", "C": "身の回りを整えれば、顧客が戻ってくる。それが先決だ。", "D": "自分のことを整理する"}},
355: {"nativeDefinition": "To treat something as unimportant.", "japaneseMeaning": "（何かを）軽く見る、なめてかかる", "etymology": "take lightly（軽く受け取る）で、重要さを軽視することを表す。", "examples": {"B": "そのテストを軽く見るべきじゃない。この科目で落ちた人は多い。", "C": "成績が下がっているのはわかるけど、授業を軽く見ているわけじゃない。", "D": "重要でないと扱う"}},
356: {"nativeDefinition": "To abandon someone to face danger alone.", "japaneseMeaning": "（人を）見捨てる、危険に晒す", "etymology": "throw to the wolves（狼に投げ込む）が比厳的に見捨てることを表す。", "examples": {"B": "トムがデパートで高価な花瓶を落とした。僕を狼に投げ込んだ。", "C": "厳しい質問を受けたとき、上司が支持してくれると思ったけど、狼に投げ込まれた。", "D": "見捨てる"}},
357: {"nativeDefinition": "Something worth thinking about seriously.", "japaneseMeaning": "考えさせられること、示唆に富む", "etymology": "food for thought（思考の糧）が比喩的に考えさせられることを表す。", "examples": {"B": "キャリアコーチが精神的に強い人がする18のことを挙げていた。考えさせられる内容だった。", "C": "マイケルと人生の意味について深い話をした。考えさせられる内容だった。", "D": "真剣に考える価値のあること"}},
358: {"nativeDefinition": "A visual representation is more effective than words.", "japaneseMeaning": "百聞は一見に如かず", "etymology": "a picture is worth a thousand words（絵は千の言葉に値する）のことわざ。", "examples": {"B": "この会社の仕組みを理解してもらうためにフローチャートを描くよ。", "C": "ピサの斜塔を知らないの？嘘でしょ。見た方が早い。ちょっと待って、写真を見せる。", "D": "言葉で説明するより視覚的に見せる方が簡単"}},
359: {"nativeDefinition": "Resolved; taken care of.", "japaneseMeaning": "対処済み、片付いた", "etymology": "taken care of（世話された）で、処理済みであることを表す。", "examples": {"B": "請求書はもう払い済みだから、何も支払う必要はない。", "C": "配送会社との問題はついに片付いた。長かった。", "D": "解決済み"}},
360: {"nativeDefinition": "To leave quietly without being noticed.", "japaneseMeaning": "こっそり抜け出す", "etymology": "sneak out（こっそり出る）で、気づかれずに出ることを表す。", "examples": {"B": "午後、会議からこっそり抜け出す必要がある。", "C": "あ、飲み物をこぼしちゃった。誰かに気づかれる前にこっそり映画館を抜け出そう。", "D": "静かに出る"}},
361: {"nativeDefinition": "To reach a critical turning point.", "japaneseMeaning": "転換点に達する、臨界点に達する", "etymology": "tipping point（傾く点）が比喩的に転換点を表す。", "examples": {"B": "地球温暖化は転換点に達した。今行動しなければ、被害は取り返しがつかなくなる。", "C": "今年、世界の経済が転換点に達した。再生可能エネルギーが50%を超えた。", "D": "重要な瞬間に到達する"}},
362: {"nativeDefinition": "To verify something for yourself.", "japaneseMeaning": "自分の目で確かめる", "etymology": "see for yourself（自分で見る）で、自分で確認することを表す。", "examples": {"B": "部屋の隅に巨大なネズミがいる。マジだよ。自分の目で確かめて。", "C": "東京は最近外国人にずっと優しくなったと思うけど、来て自分の目で確かめて。", "D": "自分で確認する"}},
363: {"nativeDefinition": "To boast about oneself.", "japaneseMeaning": "自慢する、自分を持ち上げる", "etymology": "blow one's own horn（自分のラッパを吹く）が比喩的に自慢することを表す。", "examples": {"B": "ナオミが昨日、自分を持ち上げ続ける男の話をしてくれた。うんざりした。", "C": "自慢したくはないけど、歌は本当に上手い。", "D": "自分について自慢する"}},
364: {"nativeDefinition": "Out of danger or difficulty.", "japaneseMeaning": "危機を脱した、峠を越えた", "etymology": "out of the woods（森を出た）が比喩的に危機を脱したことを表す。", "examples": {"B": "赤ちゃんは5ヶ月間酸素が必要だったけど、もう危機を脱した。元気だ。", "C": "日本経済はもう不況ではないけど、まだ完全に危機を脱したわけじゃない。", "D": "困難から抜け出た"}},
365: {"nativeDefinition": "Alternating good and bad periods.", "japaneseMeaning": "浮き沈み、良い時も悪い時も", "etymology": "ups and downs（上り下り）が比喩的に浮き沈みを表す。", "examples": {"B": "人生には浮き沈みがあると言うけど、良い時を経験したことがない気がする。", "C": "去年は自動車メーカーにとって浮き沈みの年だったけど、まだチャンスはある。", "D": "良い時と悪い時"}},
366: {"nativeDefinition": "Promising and likely to become successful.", "japaneseMeaning": "有望な、将来有望な", "etymology": "up-and-coming（上りつつある）が比喩的に将来有望を表す。", "examples": {"B": "ニューヨークにはいつも最高の有望なファッションデザイナーがいる。だから毎年行く。", "C": "この人をチェックして。有望なテック系ユーチューバーで、コンテンツが素晴らしい。", "D": "有望な"}},
367: {"nativeDefinition": "I'll deal with that problem when it actually happens.", "japaneseMeaning": "その時になってから考える、臨機応変に対処する", "etymology": "cross that bridge when I get there（その橋は着いたときに渡る）のことわざ。", "examples": {"B": "学費を払うお金がないのにスタンフォードに応募した。学費のことはその時になってから考える。", "C": "僕は臨機応変に対処するタイプだ。先のことを心配しすぎるのはやめて。", "D": "必要になったら対処する"}},
368: {"nativeDefinition": "Only just; by a very narrow margin.", "japaneseMeaning": "かろうじて、ギリギリで", "etymology": "by the skin of one's teeth（歯の皮一枚）が比喩的にかろうじてを表す。", "examples": {"B": "かろうじて大学を卒業した。期末試験でギリギリ合格した。", "C": "かろうじて会議に間に合った。1分遅れていたら入れなかった。", "D": "かろうじて"}},
369: {"nativeDefinition": "An eccentric or strange person.", "japaneseMeaning": "変人、変わり者", "etymology": "oddball（変な玉）が比喩的に変人を表す。", "examples": {"B": "ジェイクは本当に変人だ。昼食に何を食べたか聞いたら、宇宙人の話を始めた。", "C": "みんな「テイラーはちょっと変人だから近づくな」と言っていた。でも実際に話したら最高の人だった。", "D": "変な人"}},
370: {"nativeDefinition": "To take a risk on behalf of someone else.", "japaneseMeaning": "（人のために）リスクを取る、首を突っ込む", "etymology": "stick one's neck out（首を突き出す）が比喩的にリスクを取ることを表す。", "examples": {"B": "相手が同じことをしてくれないなら、他人のために首を突っ込む必要はない。", "C": "株式投資で首を突っ込むたびに切り落とされる。難しい。", "D": "リスクを取る"}},
371: {"nativeDefinition": "To rush to complete something at the last minute.", "japaneseMeaning": "（何かを）慌てて仕上げる", "etymology": "scramble to get done（這いつくばって完成させる）が比喩的に慌てて仕上げることを表す。", "examples": {"B": "今慌てて仕上げているのは、誰も早めに教えてくれなかったからだ。", "C": "職場のパーソナルアシスタントは6時間もおしゃべりして、結局慌てて仕上げることになる。", "D": "急いで何かを完成させる"}},
372: {"nativeDefinition": "A period of initial popularity or goodwill.", "japaneseMeaning": "ハネムーン期間、好評の初期段階", "etymology": "honeymoon period（新婚旅行期間）が比喩的に好評の初期段階を表す。", "examples": {"B": "カルロスは会社を立て直した英雄と見なされたが、そのハネムーン期間は長くは続かなかった。", "C": "政府はハネムーン期間中に人気のない法案を通そうとしている。", "D": "人気の期間"}},
373: {"nativeDefinition": "To make someone behave properly.", "japaneseMeaning": "（人を）しっかりさせる、行儀よくさせる", "etymology": "keep in line（列に並ばせる）が比喩的にしっかりさせることを表す。", "examples": {"B": "あの先生は生徒をしっかりさせるのが本当に上手い。", "C": "自分をしっかりさせないと、このパーティーから追い出すよ。", "D": "うまく振る舞わせる"}},
374: {"nativeDefinition": "Nobody knows; it's impossible to say.", "japaneseMeaning": "神のみぞ知る、誰にもわからない", "etymology": "God only knows（神だけが知っている）が比喩的に誰にもわからないことを表す。", "examples": {"B": "死後の世界があるかは神のみぞ知る。だから今を楽しみたい。", "C": "試験には合格できると思うけど、何が起きるかは神のみぞ知る。", "D": "わからない"}},
375: {"nativeDefinition": "A brief reminder or review.", "japaneseMeaning": "おさらい、復習", "etymology": "refresher（リフレッシュするもの）が比喩的におさらいを表す。", "examples": {"B": "このゲーム懐かしい！遊び方のおさらいが必要だ。", "C": "前回のエピソードで何が起きたかおさらいしたいなら、前シーズンの最終回を見るといい。", "D": "簡潔な思い出し"}},
376: {"nativeDefinition": "To make a gesture of peace or reconciliation.", "japaneseMeaning": "和平の申し出をする、オリーブの枝を伸ばす", "etymology": "extend an olive branch（オリーブの枝を差し出す）が聖書から転じ、和平の申し出を表す。", "examples": {"B": "時には、自分が悪くなくても、和平の申し出をする側にならなきゃいけない。", "C": "彼女と喧嘩したときは、いつも僕が和平の申し出をする側だ。", "D": "争いの解決を始める"}},
377: {"nativeDefinition": "To be overconfident before success is certain.", "japaneseMeaning": "捕らないうちに数えるな、早とちりする", "etymology": "count chickens before they hatch（孵る前に雛を数える）のことわざ。", "examples": {"B": "3点リードしているけど、早とちりするな。まだ終わっていない。", "C": "入学式のドレスを選びたいのはわかるけど、まだ合格していない。早とちりするな。", "D": "最終結果の前に過信する"}},
378: {"nativeDefinition": "To arrive gradually in small numbers.", "japaneseMeaning": "ぽつぽつと到着する、少しずつ集まる", "etymology": "trickle in（したたり込む）が比喩的に少しずつ到着することを表す。", "examples": {"B": "チームに9時に来るよう言ったけど、みんな9時半からぽつぽつと到着した。", "C": "誰も来ないかもと心配していたけど、客がぽつぽつと集まってきた。", "D": "少しずつ到着する"}},
379: {"nativeDefinition": "To increase the importance or risk of something.", "japaneseMeaning": "賭け金を上げる、重要性を高める", "etymology": "raise the stakes（賭け金を上げる）が比喩的に重要性を高めることを表す。", "examples": {"B": "優勝賞金が倍になったことで、競争の賭け金が上がった。", "C": "上司は一度も聞こうとしてくれないから、辞表を出すことで賭け金を上げることにした。", "D": "話題の重要性を高める"}},
380: {"nativeDefinition": "Without conditions or obligations.", "japaneseMeaning": "条件なしで、見返りなしで", "etymology": "no strings attached（紐なし）が比喩的に条件なしを表す。", "examples": {"B": "条件なしで半額でこの車を売るよ。どう？", "C": "毎週火曜日、角のドーナツ屋が20%オフで条件なしでくれるの知ってた？", "D": "条件が付いていない"}},
381: {"nativeDefinition": "To deliberately ignore unpleasant realities.", "japaneseMeaning": "現実から目を背ける、問題を無視する", "etymology": "bury head in sand（頭を砂に埋める）がダチョウの故事から転じ、現実逃避を表す。", "examples": {"B": "いくら現実から目を背けても、妻の浮気の問題は消えない。", "C": "この問題から目を背けられない。電車の過密は深刻な問題だ。", "D": "不快な事実を意図的に無視する"}},
382: {"nativeDefinition": "To increase effort or commitment.", "japaneseMeaning": "さらに力を入れる、倍増する", "etymology": "double down（倍にする）が比喩的にさらに力を入れることを表す。", "examples": {"B": "今年の目標は、健康と自己投資にもっと力を入れることだ。", "C": "ネットフリックスが今年アニメに力を入れると聞いて、最高のニュースだ。", "D": "もっと努力を注ぐ"}},
383: {"nativeDefinition": "To become the center of attention.", "japaneseMeaning": "注目の的になる、主役になる", "etymology": "take center stage（ステージの中央に）が比喩的に注目の的になることを表す。", "examples": {"B": "適切にマーケティングすれば、この新製品が注目の的になる。全力を尽くそう。", "C": "彼女は注目を集めたがる。いつも主役になろうとする。", "D": "多くの注目を集める"}},
384: {"nativeDefinition": "Luxurious; fit for royalty.", "japaneseMeaning": "王様にもふさわしい、豪華な", "etymology": "fit for a king（王にふさわしい）が比喩的に豪華・最高級を表す。", "examples": {"B": "ホテルの部屋は王様にもふさわしいくらい豪華だった。やりすぎかもしれないけど、大好きだ。", "C": "シェフが昨夜出した宴会料理は王様にもふさわしかった。噂では超高級食材を使ったらしい。", "D": "豪華な"}},
385: {"nativeDefinition": "A fatal weakness despite overall strength.", "japaneseMeaning": "アキレス腱、致命的な弱点", "etymology": "Achilles heel（アキレスの踵）がギリシャ神話から転じ、致命的弱点を表す。", "examples": {"B": "彼のアキレス腱は冷静さを保てないことだ。プレッシャーがかかると崩れる。", "C": "プーさんのアキレス腱は可愛さだ。たまらない。", "D": "大きな弱点"}},
386: {"nativeDefinition": "To exaggerate the importance of something.", "japaneseMeaning": "（何かを）大げさに言う、強調しすぎる", "etymology": "play up（大きく演奏する）が比喩的に大げさにすることを表す。", "examples": {"B": "子どものインターネット利用の危険性は大げさに言われすぎていると思う。", "C": "マークは週末に見た映画が史上最高だと言ったけど、大げさに言いすぎだと思う。", "D": "何かを誇張する"}},
387: {"nativeDefinition": "To break down and analyze data in detail.", "japaneseMeaning": "（データを）細かく切り分けて分析する", "etymology": "slice and dice（切って刻む）が比喩的に細かく分析することを表す。", "examples": {"B": "この世界は主観的解釈の積み重ねだ。データの切り分け方次第で見え方が変わる。", "C": "複雑な戦略を整理しようとしているけど、うまくいかない。データを細かく切り分けて分析する必要がある。", "D": "分析のために再配置する"}},
388: {"nativeDefinition": "Not fully thought through; incomplete.", "japaneseMeaning": "半端な、未完成の", "etymology": "half-baked（半焼け）が比喩的に未完成・半端を表す。", "examples": {"B": "これはまだ半端なアイデアだけど、デートアプリを作ったら面白いと思う。", "C": "コリンの事故の言い訳はかなり半端だ。隕石が車に当たったなんて誰が信じる？", "D": "粗い"}},
389: {"nativeDefinition": "A widely circulated story of doubtful truth.", "japaneseMeaning": "都市伝説", "etymology": "urban legend（都市の伝説）で、根拠の薄い噂話を表す。", "examples": {"B": "ニューヨークの下水道にワニがいるのは都市伝説じゃない。事実を基にしている。", "C": "人面犬は今まで聞いた日本の都市伝説の中で一番怖い。本当に怖い。", "D": "根拠のない話"}},
390: {"nativeDefinition": "To compel someone to act by creating pressure.", "japaneseMeaning": "（人に）行動を迫る、追い込む", "etymology": "force one's hand（手を強いる）が比喩的に追い込むことを表す。", "examples": {"B": "このワインは後で飲むつもりだったけど、トムに追い込まれて開けた。今日は彼の誕生日だから。", "C": "口臭が気になったから冗談で言っただけなのに、彼を追い込んでしまった。", "D": "誰かを追い込む"}},
391: {"nativeDefinition": "If something seems wrong, it probably is.", "japaneseMeaning": "噂をすれば影、疑わしきは罰せず", "etymology": "where there's smoke there's fire（煙があるところに火がある）のことわざ。", "examples": {"B": "リサがテストでカンニングしたと学生たちが言っている。噂をすれば影だ。", "C": "容疑者は何も悪いことはしていないと言う。でも経験上、噂をすれば影だ。", "D": "悪いことがあるようであれば、通常何かが間違っている"}},
392: {"nativeDefinition": "To suspect that something is wrong.", "japaneseMeaning": "怪しいと感じる、においを嗅ぎつける", "etymology": "smell a rat（ネズミの臭いを嗅ぐ）が比喩的に怪しいと感じることを表す。", "examples": {"B": "18歳の女の子が68歳の男と付き合っている。彼はすごいけど、怪しいと感じる。", "C": "プロフィールはアメリカ人だけど、前髪をfringesと言う。怪しい。もし会ったら確認する。", "D": "怪しいと感じる"}},
393: {"nativeDefinition": "Even good things must eventually end.", "japaneseMeaning": "良いことも終わりは来る", "etymology": "all good things must come to an end（良いことも終わりが来る）のことわざ。", "examples": {"B": "あと5時間パーティーを続けたい。でも良いことも終わりは来る。", "C": "良いことも終わりは来るのはわかっているけど、スタバにもう少しいてもいい？", "D": "楽しい経験も永遠には続かない"}},
394: {"nativeDefinition": "Ultimately; when everything is said and done.", "japaneseMeaning": "結局のところ、最終的には", "etymology": "when all's said and done で、最終的には・結局を表す。", "examples": {"B": "結局のところ、週末に何時間働いたかなんて誰も気にしない。結果だけだ。", "C": "結局のところ、どうやって勝つかは重要じゃない。何があっても勝てばいい。", "D": "最終的に"}},
395: {"nativeDefinition": "To pursue a long-term strategy.", "japaneseMeaning": "長期戦で行く、長い目で見て戦略を立てる", "etymology": "play the long game（長いゲームをする）が比喩的に長期戦略を表す。", "examples": {"B": "ティムはヨーロッパで遊んでいるだけだと思っていたけど、長期戦でビジネスを構築していた。", "C": "無給インターンは長期戦だ。今は稼げないけど、将来のための投資だ。", "D": "長期計画に基づいて行動する"}},
396: {"nativeDefinition": "The small details are what make something difficult.", "japaneseMeaning": "細部に神は宿る、悪魔は細部に宿る", "etymology": "the devil's in the detail（悪魔は細部に宿る）のことわざ。", "examples": {"B": "モーツァルトの曲は演奏するのが簡単そうに見えるけど、細部に神は宿る。", "C": "サーフィンはプロがやると簡単そうに見える。でも細部に神は宿る。すべてが完璧でなければならない。", "D": "細かい部分が正しくなるのが難しい"}},
397: {"nativeDefinition": "To have a significant advantage in a situation.", "japaneseMeaning": "すべてのカードを握っている、圧倒的に有利", "etymology": "hold all the cards（すべてのカードを握る）が比喩的に圧倒的有利を表す。", "examples": {"B": "キムは給与交渉ですべてのカードを握っている。会社が自分なしでは回らないことを知っているから。", "C": "今すべてのカードを握っているから、もっと良い条件を要求すべきだ。", "D": "大きな優位性を持つ"}},
398: {"nativeDefinition": "We had the same good idea independently.", "japaneseMeaning": "英雄所见略同、考えが同じ", "etymology": "great minds think alike（偉大な心は同じように考える）のことわざ。", "examples": {"B": "兄と僕、今日同じシャツを着ている。考えが同じだね。", "C": "サラと僕、お互いに同じクリスマスプレゼントを贈り合った。考えが同じだね。", "D": "同じ良いアイデアを持っていた"}},
399: {"nativeDefinition": "A comfortable and enjoyable way of living.", "japaneseMeaning": "良い生活、豊かな暮らし", "etymology": "the good life（良い人生）で、豊かで快適な生活を表す。", "examples": {"B": "彼のインスタの休暇写真を見ると幸せになる。あれこそ良い生活だ。", "C": "ジェレミーは生まれながらの金持ちだ。両親が良い生活を与えてくれた。", "D": "質の高い暮らし方"}},
400: {"nativeDefinition": "To have someone under one's control.", "japaneseMeaning": "（人を）手のひらの上で転がす、従わせている", "etymology": "have on a leash（リードにつなぐ）が比喩的にコントロール下にあることを表す。", "examples": {"B": "彼は上司の手のひらの上で転がされている。いつも指示を仰いでいる。", "C": "彼女は彼氏を手のひらの上で転がしている。何を言っても従う。", "D": "コントロール下にある"}},
}
